INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Recruitment and onboarding$q$, $q$Applicant tracking, interview scheduling, and structured onboarding checklists to move new hires from application to first day.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Attendance and leave management$q$, $q$Configurable shift and attendance tracking paired with customizable leave types, accrual rules, and approval workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Payroll processing$q$, $q$Built-in payroll calculation and payslip generation that integrates with attendance and leave data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Performance management$q$, $q$Goal setting, periodic reviews, and 360-degree feedback cycles for tracking employee development.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Asset management$q$, $q$Assign, track, and reclaim company equipment and IT assets tied to individual employee records.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Built-in CRM$q$, $q$Lead capture and sales pipeline tracking bundled alongside the HR modules for small teams that need both.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Offboarding workflows$q$, $q$Structured exit checklists to formalize asset return, access revocation, and final settlements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$REST API and self-hosting$q$, $q$Full source-code access, an open REST API, and LGPL-2.1 licensing for custom integrations and unlimited self-hosted users.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Free, unlimited-user self-hosted edition with no per-employee licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Combines HR and CRM functionality in a single open-source platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Broad module coverage spanning the full employee lifecycle$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Active GitHub development community and regular updates$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Managed Cloud tier removes the need to run your own infrastructure$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Self-hosting requires technical staff to install, secure, and maintain the application$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Third-party integrations and documentation are less mature than established HRIS incumbents$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Community support on the free tier has no guaranteed response time$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Newer project with a smaller long-term track record than BambooHR or Zoho People$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Advanced payroll compliance for some countries may require custom development$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Is Horilla really free to use?$q$, $q$Yes. The self-hosted, open-source edition of Horilla is free forever with unlimited users and companies, licensed under LGPL-2.1. Paid Cloud and Enterprise tiers are optional for teams that want managed hosting and support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Who develops Horilla?$q$, $q$Horilla is built and maintained by Cybrosys Technologies, an Odoo implementation partner headquartered in Kerala, India, along with an open-source community of contributors on GitHub.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Does Horilla include payroll?$q$, $q$Yes, Horilla includes a payroll module that calculates pay based on attendance and leave records and generates payslips.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Can Horilla be self-hosted?$q$, $q$Yes, self-hosting is the default free option. Organizations download the source from GitHub and deploy it on their own servers or cloud infrastructure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$What does Horilla Cloud cost?$q$, $q$Horilla Cloud starts at $7 per user per month, billed monthly, with a 30-day free trial and managed infrastructure, backups, and support.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Does Horilla have a CRM?$q$, $q$Yes, Horilla bundles a lightweight CRM module for lead and sales pipeline tracking alongside its HR features.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Cost-conscious SMB HR management$q$, $q$Small and mid-sized businesses can run full HR operations, from recruitment to payroll, without paying per-employee SaaS fees by self-hosting Horilla.$q$, $q$Small and mid-sized business HR teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Combined HR and CRM for lean teams$q$, $q$Startups can manage both employee operations and sales pipelines in one open-source system instead of paying for separate HR and CRM tools.$q$, $q$Startups and lean operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Custom-compliance HR deployments$q$, $q$Organizations with country-specific labor or payroll rules can modify Horilla's open-source modules to match local compliance needs that off-the-shelf SaaS HRIS platforms do not support.$q$, $q$IT teams and consultancies with custom compliance requirements$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$Forever$q$, NULL, $q$["Unlimited users and companies","Full HRMS and CRM modules","Community support via GitHub","All future updates","LGPL-2.1 licensed source code"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Horilla Cloud$q$, $q$$7/user/month$q$, $q$Monthly$q$, NULL, $q$["Managed hosting with daily backups","Zero-downtime auto-updates","SSL and custom domain","Priority email support (48-hour SLA)","99.9% uptime guarantee","30-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["On-premises or private-cloud deployment","SSO via SAML 2.0, OAuth, or LDAP","Dedicated account manager","4-hour response SLA, 99.95% uptime","White-labeling and custom integrations","Priority implementation support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Horilla is an open-source human resource management system designed to give growing companies the functional depth of a commercial HRIS without a recurring per-employee license fee. Built by Cybrosys Technologies, an established Odoo implementation partner based in Kerala, India, Horilla brings ERP-style modularity to HR: each function, from recruitment to payroll, is a self-contained app that can be enabled, configured, or extended independently.$q$, $q$Unlike many single-purpose HR tools, Horilla also bundles a lightweight CRM for tracking leads and sales pipelines, making it appealing to small businesses that want one open-source system covering both people operations and customer relationships rather than stitching together separate SaaS subscriptions.$q$, $q$The software is distributed under the LGPL-2.1 license and hosted publicly on GitHub, where an active community contributes bug fixes, translations, and new modules. Organizations can self-host it for free, or offload infrastructure management to Cybrosys via a managed Cloud or Enterprise plan.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Horilla covers the full employee lifecycle: applicant tracking and recruitment pipelines, structured onboarding checklists, a central employee database, biometric-friendly attendance tracking, configurable leave policies and approval chains, IT and physical asset assignment, payroll processing, goal-based performance management with 360-degree feedback, and formal offboarding workflows.$q$, $q$On the CRM side, Horilla adds lead capture, pipeline stages, and deal tracking, letting small teams manage sales alongside HR from the same login and permission system rather than paying for a second platform.$q$, $q$Because it is open source, Horilla exposes a REST API and a customizable module system, so technical teams can build integrations with payroll processors, accounting software, and job boards, or modify workflows to match country-specific labor rules that off-the-shelf SaaS HRIS tools often fail to support out of the box.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Horilla's self-hosted edition is free forever with unlimited users and companies, making it one of the few HRMS platforms with no user-count ceiling on the free tier; the tradeoff is that the organization must provision servers, apply updates, and handle its own backups and security.$q$, $q$Teams that want the same feature set without operational overhead can subscribe to Horilla Cloud starting at $7 per user per month with a 30-day free trial, which adds managed hosting, daily backups, automatic updates, SSL, and priority support. Enterprises with compliance or scale requirements can move to a custom-priced Enterprise plan with SSO, dedicated support, and on-premises or private-cloud deployment options.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
