INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6c4d248e-ed75-425f-a74f-2cfa5f36dc03', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Plant cataloging$q$, $q$Add individual plants with photos, species details, acquisition dates, and assigned locations within a home or garden.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Care warning system$q$, $q$Automatic flags for plants that need watering, fertilizing, or repotting based on user-defined schedules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Collaborative multi-user access$q$, $q$Shared collections with authenticated user accounts, ideal for households, community gardens, or plant shops.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Group chat and history log$q$, $q$Built-in messaging between users and a full audit trail of who took which action on each plant.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Task calendar and weather integration$q$, $q$Centralized calendar of upcoming care tasks with weather data to inform outdoor plant care.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Inventory management$q$, $q$Track supplies like soil, pots, and fertilizer alongside the plant collection itself.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$REST API$q$, $q$An API introduced in version 3.1 for building custom integrations and automations on top of HortusFox.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Progressive web app$q$, $q$Installable on mobile home screens without an app store, giving an app-like experience from a self-hosted instance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Completely free and open source under the permissive MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Full data ownership since the app is self-hosted on infrastructure the user controls$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Built-in collaboration features like shared collections and group chat are rare among plant-tracking apps$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Lightweight PHP and MariaDB/MySQL stack that runs on inexpensive shared hosting or a home server$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Active open-source development with a REST API for custom integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Requires self-hosting, which means installing and maintaining a server rather than downloading a consumer app$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$No official managed hosting or support plan from the project itself$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Smaller community and plant database compared to commercial apps like Planta$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$No native iOS or Android app; relies on progressive web app behavior in the browser$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Founding history, team size, and roadmap are not formally documented, which may concern risk-averse adopters$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Is HortusFox free to use?$q$, $q$Yes, HortusFox is fully free and open source under the MIT license. The only cost is hosting it on your own server or a paid third-party host.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Do I need to self-host HortusFox?$q$, $q$Yes, HortusFox is designed to be self-hosted. It can be deployed via Docker, one-click installers on platforms like Cloudron or elest.io, or a manual PHP and MariaDB/MySQL setup.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Who created HortusFox?$q$, $q$HortusFox was created by developer Daniel Brendel and is maintained as an open-source project under the hortusfox GitHub organization.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Can multiple people share one HortusFox instance?$q$, $q$Yes, HortusFox supports multiple authenticated user accounts that can share a collection, chat with each other, and see a history log of care actions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Does HortusFox have a mobile app?$q$, $q$HortusFox works as a progressive web app that can be added to a phone's home screen, but there is no separate native iOS or Android app.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Does HortusFox have an API?$q$, $q$Yes, a REST API was introduced in version 3.1, allowing developers to build custom integrations on top of a HortusFox instance.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Personal houseplant tracking$q$, $q$Hobbyists with large plant collections can log species, locations, and care schedules in one self-hosted, privacy-respecting dashboard.$q$, $q$Individual houseplant collectors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Shared household plant management$q$, $q$Families or roommates can jointly manage plant care duties using shared logins, chat, and a history log of who watered or repotted what.$q$, $q$Households and roommates$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Community garden and plant shop inventory$q$, $q$Groups managing a shared plant inventory, such as community gardens or small plant shops, can use multi-user access and admin controls to coordinate care.$q$, $q$Community gardens and small plant retailers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$Forever$q$, NULL, $q$["Full source code under MIT license","Unlimited plants and users","Collaborative multi-user access","REST API access","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HortusFox is an open-source, self-hosted application for cataloging and caring for a plant collection, built by developer Daniel Brendel for plant owners who want full control over their own data rather than relying on a commercial cloud service. It runs on a standard PHP and MariaDB/MySQL stack and is delivered as a progressive web app, so it works well on both desktop and mobile without needing a native app store listing.$q$, $q$The project is aimed squarely at the growing community of tech-savvy houseplant collectors who track dozens or hundreds of individual plants and want structured record-keeping, care reminders, and the option to share access with family members or fellow hobbyists.$q$, $q$Because there is no company or subscription model behind it, HortusFox is distributed under the MIT license on GitHub, and anyone can deploy their own instance for free using Docker, one-click installers on platforms like Cloudron and elest.io, or a manual PHP hosting setup.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, HortusFox lets users add plants with photos, species information, and location assignments, then view everything on a dashboard that surfaces which plants need attention. A warning system flags overdue watering, fertilizing, or repotting based on schedules the user configures per plant.$q$, $q$Collaboration is a defining feature: multiple authenticated users can share a single collection, chat with each other inside the app, and see a full history log of who added, edited, or cared for which plant. This makes HortusFox useful for households, community gardens, or plant shops with several staff members managing the same inventory.$q$, $q$Supporting features include a supply inventory for tracking pots and soil, a task calendar, weather integration for outdoor care planning, customizable themes and profiles, admin controls for multi-user instances, and a REST API introduced in version 3.1 for building custom integrations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HortusFox is entirely free and open source under the MIT license; there is no paid tier, subscription, or freemium gate built into the software itself. The only cost involved is whatever server or hosting infrastructure the user chooses to run it on, which can range from a few dollars a month on a budget VPS to free on existing home-lab hardware.$q$, $q$Some third-party platforms, such as Cloudron and elest.io, offer paid one-click hosting for HortusFox as a convenience for users who don't want to manage a server themselves, but these are independent hosting services rather than an official HortusFox pricing plan, and the project explicitly disclaims responsibility for third-party hosting quality.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a0a11055-ce1c-48de-8c3b-a99cd8a998eb', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$hPanel custom control panel$q$, $q$A proprietary, beginner-friendly hosting dashboard that replaces traditional cPanel with a more visual, simplified interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$NVMe SSD storage and CDN$q$, $q$Fast NVMe-based storage paired with a bundled content delivery network for improved site load times.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$AI-assisted website builder$q$, $q$A drag-and-drop, no-code builder with AI content and design suggestions, plus built-in ecommerce tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Automated backups$q$, $q$Weekly to daily automated backups depending on plan tier, with on-demand backup options on higher plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Free domain and SSL$q$, $q$A free domain for the first year and a free SSL certificate bundled into hosting plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$VPS and cloud hosting$q$, $q$Self-managed and managed VPS and cloud plans with root access for developers running custom applications.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Malware scanning and domain privacy$q$, $q$Built-in security scanning and WHOIS privacy protection included across hosting tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$24/7 multilingual support$q$, $q$Round-the-clock live chat support in multiple languages, supplemented by the Kodee AI assistant and knowledge base.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Aggressively low promotional pricing that undercuts most mainstream hosting competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$hPanel offers one of the most beginner-friendly hosting dashboards in the industry$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Fast shared-hosting performance thanks to NVMe storage and a bundled CDN$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Bundled AI website builder and ecommerce tools reduce the need for separate services$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$30-day money-back guarantee and 24/7 support across most plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Renewal pricing after the initial promotional term can be substantially higher$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Advanced customization options are more limited than full cPanel-based hosts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Customer support has shifted heavily toward AI-assisted responses, which can feel less personal$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Best pricing requires long-term commitments of 24 to 48 months$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Some users report limited flexibility for advanced domain and account management$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$When was Hostinger founded?$q$, $q$Hostinger was founded in 2004 in Kaunas, Lithuania, originally as a company called Hosting Media, and rebranded to Hostinger in 2011.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$How much does Hostinger cost?$q$, $q$Hostinger's shared hosting plans start around $2.99 per month on a discounted long-term promotional rate, with Unlimited and Cloud Startup tiers priced higher for more resources.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Does Hostinger include a free domain?$q$, $q$Yes, most Hostinger hosting plans include a free domain name for the first year of service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$What is hPanel?$q$, $q$hPanel is Hostinger's proprietary, custom-built hosting control panel that replaces traditional cPanel with a simplified, more visual interface.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Does Hostinger offer a website builder?$q$, $q$Yes, Hostinger includes an AI-assisted, no-code drag-and-drop website builder with ecommerce features, bundled into most hosting plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Is Hostinger good for beginners?$q$, $q$Yes, Hostinger is widely regarded as one of the more beginner-friendly hosting providers due to hPanel's simplified interface, though renewal pricing and support depth are worth reviewing before committing long-term.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$First website launch$q$, $q$Individuals and freelancers launching their first blog or portfolio site can use Hostinger's low-cost shared hosting and drag-and-drop builder to get online quickly.$q$, $q$Individuals, freelancers, and bloggers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Small business ecommerce$q$, $q$Small businesses can combine Hostinger's Website Builder ecommerce tools with hosting and a bundled domain to launch an online store affordably.$q$, $q$Small businesses and online sellers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Developer and agency VPS hosting$q$, $q$Developers and agencies can deploy client projects or custom applications on Hostinger's self-managed VPS and cloud plans with root access.$q$, $q$Developers and web agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Premium$q$, $q$From $2.99/month (promotional)$q$, $q$Long-term commitment (monthly rate shown)$q$, NULL, $q$["3 websites","20 GB SSD storage","Free domain for 1 year","Weekly backups","Bundled CDN","2 mailboxes per website"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Unlimited$q$, $q$From $3.79/month (promotional)$q$, $q$Long-term commitment (monthly rate shown)$q$, NULL, $q$["Unlimited websites and mailboxes","50 GB NVMe storage","Daily backups","Bundled CDN","Free domain for 1 year"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$Cloud Startup$q$, $q$From $7.99/month (promotional)$q$, $q$Long-term commitment (monthly rate shown)$q$, NULL, $q$["Unlimited websites","100 GB NVMe storage","Daily and on-demand backups","Bundled CDN","Free domain for 1 year","Unlimited mailboxes"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hostinger is one of the largest web hosting providers globally, founded in 2004 in Kaunas, Lithuania, and built into a bootstrapped, privately held company generating hundreds of millions of dollars in annual recurring revenue without outside venture funding. What started as a small hosting business named Hosting Media grew through international brand expansion, most notably rebranding to Hostinger in 2011 under CEO Arnas Stuopelis.$q$, $q$The company's flagship differentiator is hPanel, a proprietary control panel built to replace the dated cPanel interface with a simpler, more visual dashboard aimed at hosting beginners, alongside deeply discounted long-term pricing that has made it one of the most recognizable budget hosting brands worldwide.$q$, $q$Beyond core hosting, Hostinger has expanded into a broader small-business toolkit that includes an AI-assisted, no-code website builder, domain registration, managed WordPress hosting, VPS and cloud infrastructure, and email hosting, positioning itself as a one-stop platform for launching and running a website rather than a pure infrastructure provider.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hostinger's shared and cloud hosting plans include NVMe SSD storage, free SSL certificates, malware scanning, domain privacy, automated backups, and a bundled content delivery network, with higher tiers unlocking unlimited websites, unlimited mailboxes, and dedicated cloud resources for more demanding sites.$q$, $q$The Hostinger Website Builder offers drag-and-drop page editing, AI-generated content and layout suggestions, ecommerce functionality for selling products online, and AI-driven email marketing tools bundled free for the first year on higher plans, aimed at users who want to launch a site without touching code.$q$, $q$For more technical users, Hostinger also offers self-managed and managed VPS hosting with root access, one-click app installers, and developer tools, positioning the platform to serve both non-technical beginners and developers deploying custom applications on the same underlying infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hostinger's shared hosting is sold in three main tiers, typically discounted heavily for customers who commit to longer terms such as 24 or 48 months. Premium starts around $2.99 per month promotionally (regular price near $11.99), Unlimited starts around $3.79 per month (regular near $18.99) with unlimited websites and mailboxes, and Cloud Startup starts around $7.99 per month (regular near $27.99) with dedicated cloud-level resources.$q$, $q$All plans include a free SSL certificate, a free domain for the first year, a 30-day money-back guarantee, and 24/7 support. Because Hostinger's advertised pricing depends heavily on long commitment terms and renews at a significantly higher rate, prospective customers should check the regular (non-promotional) renewal price before committing, since this is one of the most common criticisms in independent reviews.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
