INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c25e7433-44ad-439d-a4df-0347e6f2e9c2', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Heatmaps$q$, $q$Click, move, and scroll heatmaps that visualize aggregate visitor attention and engagement across a webpage.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Session recordings$q$, $q$Anonymized replays of individual visitor sessions with filters for rage clicks, dead clicks, and navigation loops.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$On-site surveys$q$, $q$No-code, responsive surveys distributed via embedded widgets, links, or email to collect qualitative feedback in context.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Feedback widgets$q$, $q$Always-on feedback buttons that let visitors report issues or share sentiment while browsing a site.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Funnel and form analysis$q$, $q$Tools to identify where visitors drop off in a conversion funnel or abandon a form field.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Recruiting panel$q$, $q$A feature for sourcing real users for interviews and usability testing directly from Hotjar's audience.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$GDPR and CCPA-aligned privacy controls$q$, $q$Data anonymization, retention settings, and compliance tooling for collecting behavioral data responsibly.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Integrations$q$, $q$Native integrations with Google Analytics, Slack, and popular CMS and ecommerce platforms for combining quantitative and qualitative data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Fast setup with a single JavaScript snippet and no engineering resources required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Combines heatmaps, session recordings, and surveys in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Free Basic tier makes it accessible for small sites and early-stage products$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Widely adopted with strong brand recognition and a large respondent network for surveys$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Useful for surfacing concrete usability issues like broken checkout steps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Free and lower-tier plans have restrictive daily session and monthly response caps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Historically required separate subscriptions for Observe and Ask, adding cost complexity$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Support is largely ticket-based with response times of one to two business days$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Limited advanced segmentation for filtering heatmap data$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Less effective for tracking dynamic, single-page application interactions compared to some competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Is Hotjar free to use?$q$, $q$Yes, Hotjar offers a free Basic tier for both its Observe (heatmaps and recordings) and Ask (surveys) products, with limited daily sessions or monthly responses.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Who owns Hotjar?$q$, $q$Hotjar was founded independently in Malta in 2014 by David Darmanin and co-founders, and was acquired by Contentsquare in September 2021.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$What is the difference between Hotjar Observe and Ask?$q$, $q$Observe covers heatmaps and session recordings for visualizing user behavior, while Ask covers surveys and feedback widgets for collecting qualitative visitor feedback.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$How much does Hotjar cost?$q$, $q$Hotjar's paid plans historically start around $39 per month for Observe Plus and EUR 48 per month for Ask Plus, with pricing migrating to a unified Contentsquare structure starting around $49 per month in 2026.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Does Hotjar work with single-page applications?$q$, $q$Hotjar can track single-page applications, but reviewers note it is somewhat less robust for fully dynamic apps compared to tools built specifically for SPA tracking.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$What companies use Hotjar?$q$, $q$Hotjar reports being used on more than 1.3 million websites, including large brands such as Nintendo, Adobe, T-Mobile, and HubSpot.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Conversion rate optimization$q$, $q$CRO specialists use heatmaps and funnel analysis to identify where visitors drop off and prioritize which page elements to test.$q$, $q$Conversion rate optimization and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$UX research and usability testing$q$, $q$Product and UX teams replay session recordings and recruit real users through Hotjar's panel to diagnose usability problems.$q$, $q$UX researchers and product managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Customer feedback collection$q$, $q$Marketing and support teams deploy on-site surveys and feedback widgets to capture qualitative visitor sentiment at scale.$q$, $q$Marketing and customer experience teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Observe Basic / Ask Basic$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["35 daily sessions (Observe)","20 monthly responses (Ask)","Basic heatmaps and recordings","Basic survey creation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Plus$q$, $q$From $39/month (Observe); EUR 48/month (Ask)$q$, $q$Monthly or annual$q$, NULL, $q$["100 daily sessions (Observe)","250 monthly responses (Ask)","Expanded heatmap and recording history","More survey customization"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Business$q$, $q$From $99/month (Observe); EUR 64/month (Ask)$q$, $q$Monthly or annual$q$, NULL, $q$["500 daily sessions (Observe)","500 monthly responses (Ask)","Advanced filtering","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$Scale$q$, $q$From $213/month (Observe); EUR 128/month (Ask)$q$, $q$Monthly or annual$q$, NULL, $q$["1,500 daily sessions (Observe)","Higher response volumes (Ask)","Extended data retention","Advanced team collaboration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hotjar is a behavior analytics platform founded in 2014 in Malta by David Darmanin and a small founding team, built from the outset as a self-funded, fully remote company. It became one of the most widely recognized names in qualitative web analytics by combining visual heatmaps, session recordings, and on-site surveys into a single, easy-to-install product.$q$, $q$In September 2021, Hotjar was acquired by Contentsquare, a larger digital experience analytics company, in what was Contentsquare's sixth acquisition in two years. The combined organization now exceeds 1,000 employees, and while Hotjar continues to operate under its own brand and product experience, its pricing and platform are gradually being unified with Contentsquare's broader suite.$q$, $q$The product installs via a single JavaScript snippet and requires no engineering resources to configure basic heatmaps or recordings, which has made it a popular first analytics tool for marketing and product teams who want to see, not just measure, how visitors use their site.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hotjar's Observe product includes click, move, and scroll heatmaps that visualize aggregate user attention on a page, alongside session recordings that let teams watch anonymized replays of individual visitor journeys, complete with filters for rage clicks, dead clicks, and u-turns that flag likely usability problems.$q$, $q$The Ask product covers on-site surveys, embedded feedback widgets, and external survey links, letting teams gather qualitative context behind the quantitative patterns seen in Observe, plus a recruiting panel feature for sourcing participants for user interviews and usability testing.$q$, $q$Supporting features include funnel and form analysis to pinpoint where visitors abandon a conversion flow, integrations with tools like Google Analytics, Slack, and various CMS and ecommerce platforms, and GDPR/CCPA-aligned data collection controls including IP anonymization and data retention settings.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hotjar has historically sold Observe and Ask as two separate subscriptions, each with a free Basic tier. Observe's free tier includes 35 daily sessions, with paid Plus, Business, and Scale tiers priced roughly at $39, $99, and $213 per month respectively at monthly billing (lower with annual billing), scaling session volume up to 1,500 daily sessions. Ask's free tier includes 20 monthly survey responses, with paid tiers priced roughly at EUR 48, EUR 64, and EUR 128 per month for increasing response volumes.$q$, $q$Following the Contentsquare acquisition, Hotjar is being migrated toward a unified Contentsquare pricing model in 2026, introducing Growth, Pro, and Enterprise tiers, with Growth starting around $49 per month and Pro and Enterprise requiring a custom quote from sales. Existing self-serve customers are being transitioned gradually, so pricing may vary depending on when an account was created.$q$]::text[], 2);
