INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('65ed3bfb-065e-4391-8e0f-5ffc7b205daa', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$No-code survey builder$q$, $q$Drag-and-drop editor for creating responsive surveys without writing any code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$On-site survey widgets$q$, $q$Surveys triggered directly on a webpage based on visitor behavior such as scroll depth or exit intent.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Link and email distribution$q$, $q$Ability to share surveys as a standalone link or send them via email outside the website context.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Question branching and skip logic$q$, $q$Conditional logic that adapts follow-up questions based on a respondent's previous answers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Permanent response storage$q$, $q$Survey responses are stored permanently on paid plans for long-term analysis and reporting.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$GDPR and CCPA-aligned privacy controls$q$, $q$Data handling built to align with major privacy regulations for collecting visitor feedback responsibly.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Cross-device responsive design$q$, $q$Surveys automatically adapt their layout for desktop, tablet, and mobile respondents.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Integration with Hotjar behavior data$q$, $q$Survey responses can be reviewed alongside heatmaps and session recordings for the same visitors.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Free tier with no credit card required, offering up to 20 responses per month$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Deep integration with Hotjar's heatmaps and session recordings for combined quantitative and qualitative insight$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$No-code builder makes it accessible to marketing and product teams without developer support$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Flexible distribution via on-site widget, link, or email$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Large existing respondent network drawn from Hotjar's 1.3 million-plus website install base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Free tier's 20-response monthly cap is limiting for anything beyond small-scale testing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Historically priced as a separate subscription from Hotjar's Observe product, adding cost complexity$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Less advanced branching and logic than dedicated survey specialists like Typeform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Support is largely ticket-based with multi-day response times$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Pricing is in transition as Hotjar migrates to unified Contentsquare plans, creating some uncertainty for new buyers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Is Hotjar Surveys free to use?$q$, $q$Yes, Hotjar Surveys offers a free Basic tier with up to 20 responses per month and no credit card required. Paid plans unlock unlimited surveys and higher response volumes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$How is Hotjar Surveys different from Hotjar heatmaps?$q$, $q$Hotjar Surveys is part of Hotjar's Ask product and focuses on collecting direct, qualitative visitor feedback, while heatmaps and session recordings are part of the Observe product and focus on visualizing quantitative behavior.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Can Hotjar Surveys be sent via email?$q$, $q$Yes, surveys can be distributed as an on-site widget, a standalone shareable link, or sent directly via email.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$How much does Hotjar Surveys cost on paid plans?$q$, $q$Paid Ask tiers have historically started around EUR 48 per month for 250 responses, scaling up to EUR 128 per month for higher volumes, though pricing is migrating to a unified Contentsquare structure in 2026.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Does Hotjar Surveys support branching logic?$q$, $q$Yes, surveys support question branching and skip logic based on a respondent's previous answers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Who makes Hotjar Surveys?$q$, $q$Hotjar Surveys is built by Hotjar, founded in Malta in 2014 and acquired by Contentsquare in 2021.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$In-context website feedback$q$, $q$Teams trigger on-site survey widgets based on visitor behavior to capture feedback about specific pages or flows while intent is fresh.$q$, $q$Product and UX teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Post-purchase and NPS surveys$q$, $q$Ecommerce and SaaS teams send email-based surveys to gather satisfaction scores and open-ended feedback after a purchase or key interaction.$q$, $q$Customer experience and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Combined behavior and feedback analysis$q$, $q$Growth teams pair survey responses with heatmap and session recording data from the same visitors to understand both what happened and why.$q$, $q$Growth and conversion optimization teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Basic$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["Up to 20 responses per month","No-code survey builder","On-site, link, and email distribution","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Plus$q$, $q$Approximately EUR 48/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 250 responses per month","Unlimited surveys","Permanent response storage","Question branching and logic"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Business$q$, $q$Approximately EUR 64/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 500 responses per month","Advanced filtering","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$Scale$q$, $q$Approximately EUR 128/month$q$, $q$Monthly or annual$q$, NULL, $q$["Higher response volumes","Extended data retention","Advanced team collaboration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hotjar Surveys is the feedback-collection component of Hotjar's Ask product suite, letting teams build no-code surveys and deploy them directly on their website, via link, or through email. It is built and maintained by Hotjar, the Malta-founded behavior analytics company acquired by Contentsquare in 2021.$q$, $q$The tool is designed to sit alongside Hotjar's heatmaps and session recordings so teams can pair quantitative behavior data with qualitative visitor feedback, answering not just what users did on a page but why they did it.$q$, $q$Hotjar reports that its surveys have collected responses from more than 402 million respondents across over 180 countries, reflecting broad adoption across the more than 1.3 million websites that use Hotjar's products.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Surveys can be built with a drag-and-drop, no-code editor and deployed as an on-site widget triggered by rules like time on page, scroll depth, or exit intent, as a standalone link, or sent via email to an existing customer or subscriber list.$q$, $q$The product supports permanent response storage on paid plans, question branching and skip logic, and responsive design that adapts survey layout across desktop and mobile visitors.$q$, $q$Privacy and compliance features include GDPR and CCPA-aligned data handling, and because Surveys is part of the broader Hotjar platform, response data can be viewed alongside session recordings and heatmap data for the same visitors where available.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hotjar Surveys is available on a free Basic tier that allows up to 20 responses per month with no credit card required, making it accessible for testing or low-traffic sites. Paid tiers unlock unlimited surveys and higher monthly response volumes.$q$, $q$Historically, paid Ask tiers were priced separately from Hotjar's Observe product at roughly EUR 48 per month for Plus (250 responses), EUR 64 per month for Business (500 responses), and EUR 128 per month for Scale. As part of the broader Contentsquare integration, Hotjar is migrating self-serve customers to a unified pricing structure through 2026, so current published pricing may differ by account.$q$]::text[], 2);
