INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('00ea990a-f3f1-4733-b437-22705a46609d', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Online booking$q$, $q$Customers can self-schedule appointments 24/7 through Google search results or a business's own website.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Scheduling and dispatching$q$, $q$A visual, drag-and-drop job board for assigning technicians to jobs and managing daily schedules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Invoicing and payments$q$, $q$Automated invoicing with payment reminders and in-app card processing for on-site or remote payment collection.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Quotes and proposals$q$, $q$Text- or email-based quotes and, on higher tiers, a dedicated sales proposal tool for upselling services.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Route optimization$q$, $q$Real-time, traffic-based route reordering to reduce technician drive time between jobs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Photo reports and GPS tracking$q$, $q$Photo documentation with annotation tools and employee GPS tracking for field visibility.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$QuickBooks Online sync$q$, $q$Two-way synchronization with QuickBooks Online for streamlined accounting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Open API access$q$, $q$API access on the Max plan for building custom integrations with other business systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Combines scheduling, invoicing, payments, and customer communication in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Strong customer support reputation, including an active user community$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Easy-to-use drag-and-drop scheduling and built-in phone system$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Free mobile apps for iOS and Android used by field technicians$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Scales from solo operators to larger teams across three pricing tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Pricing can be steep for very small, one- or two-person operations$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Mobile app can be glitchy at times according to user reviews$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Reporting and data export features are less robust than some competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Web interface can feel dated and clunky compared to newer field service tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Mobile app functionality is limited when offline, restricting field use in low-connectivity areas$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$How much does Housecall Pro cost?$q$, $q$Housecall Pro starts at $59 per month billed annually for the Basic plan with one user, with Essentials at $149 per month and Max at $299 per month for larger teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Who founded Housecall Pro?$q$, $q$Housecall Pro was founded in 2013 in San Diego, California, by Ian Heidt, Roland Ligtenberg, Reza Olfat, Adam Perry-Pelletier, and Chris Zwickilton.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Does Housecall Pro have a mobile app?$q$, $q$Yes, Housecall Pro offers free native iOS and Android apps for field technicians that sync in real time with the web-based office dashboard.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$What trades use Housecall Pro?$q$, $q$Housecall Pro is used by home service businesses including HVAC, plumbing, electrical, cleaning, landscaping, and pest control companies.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Does Housecall Pro integrate with QuickBooks?$q$, $q$Yes, Housecall Pro offers two-way synchronization with QuickBooks Online starting on its Essentials plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$How many users are included in each Housecall Pro plan?$q$, $q$Basic includes 1 user, Essentials includes up to 5 users, and Max includes up to 8 users, with additional users on Max available for $35 per month each.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Solo contractor scheduling and invoicing$q$, $q$A single-operator home service business can use the Basic plan to manage online booking, invoicing, and payments without an office staff.$q$, $q$Solo contractors and small trade businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Growing team dispatch and operations$q$, $q$Multi-technician businesses can use the Essentials plan to manage routes, checklists, photo reports, and technician commissions across a small team.$q$, $q$Growing field service teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Scaling home service operations$q$, $q$Larger home service companies can use the Max plan's route optimization, open API, and recurring service plans to manage complex, high-volume operations.$q$, $q$Scaling home service companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Basic$q$, $q$$59/month (annual) or $79/month (monthly)$q$, $q$Annual or monthly$q$, NULL, $q$["1 user included","Online booking","Invoicing and payments","Scheduling and dispatching","Quotes and proposals","Review management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Essentials$q$, $q$$149/month (annual) or $189/month (monthly)$q$, $q$Annual or monthly$q$, NULL, $q$["Up to 5 users included","Everything in Basic","Route optimization","Flat-rate pricing","Checklist automations","Photo reports","Employee GPS tracking","QuickBooks Online sync"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$Max$q$, $q$$299/month (annual) or $329/month (monthly)$q$, $q$Annual or monthly$q$, NULL, $q$["Up to 8 users included ($35/month per additional user)","Everything in Essentials","Sales proposal tool","Recurring service plans","Real-time route optimization","Open API access","Dedicated onboarding specialist"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Housecall Pro is a field service management platform built for home service businesses such as HVAC, plumbing, electrical, cleaning, and landscaping companies. It was founded in 2013 in San Diego, California, by Ian Heidt, Roland Ligtenberg, Reza Olfat, Adam Perry-Pelletier, and Chris Zwickilton, and today operates primarily out of Denver, Colorado, with over 200,000 home service professionals on the platform.$q$, $q$The company has raised more than $174 million in funding from investors including Permira and Vista Credit Partners, backing continued expansion of its scheduling, payments, and marketing tools for trade businesses.$q$, $q$Housecall Pro pairs a web-based office dashboard with free mobile apps for field technicians, letting office staff and crews stay synchronized on job status, customer details, and payments in real time from any location.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core workflow covers 24/7 online booking, drag-and-drop scheduling and dispatching, text- and email-based quotes, automated invoicing with payment reminders, and integrated card processing so technicians can collect payment on-site.$q$, $q$Higher-tier plans add route optimization, flat-rate pricing books, photo reports with annotation, employee GPS tracking, commission tracking for technicians, two-way QuickBooks Online sync, recurring service plan management, and an open API for custom integrations.$q$, $q$Review management tools help businesses collect and showcase customer testimonials, while a built-in sales proposal tool on the top tier helps technicians upsell additional services directly from the field.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Housecall Pro is sold in three tiers priced per month with annual billing offering a discount over monthly billing. Basic starts at $59 per month annually for one user, Essentials at $149 per month annually for up to five users, and Max at $299 per month annually for up to eight users, with additional users on Max priced at $35 per month each.$q$, $q$Each tier is cumulative, meaning Essentials includes everything in Basic and Max includes everything in Essentials, with feature access expanding alongside user count. All plans include live chat and phone support, free mobile apps, and card processing at roughly 2.59 percent per transaction.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('bbbaf42a-877b-4574-bbcf-56a9d704be00', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
