-- Enrichment marathon batch: Horilla, HortusFox, Hostinger, Hotjar, Hotjar Surveys, Housecall Pro, HTMLy, HTTPie

-- ── Horilla ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Horilla is a free, open-source HR and CRM platform covering recruitment, payroll, attendance, and performance management.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (Open Source self-hosted, plus paid Cloud and Enterprise tiers)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); Cloud from $7/user/month$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Kozhikode, Kerala, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Horilla Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Horilla is a free, open-source HRMS with recruitment, payroll, attendance, and performance modules. See 2026 pricing, features, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Horilla is a free, open-source Human Resource Management System built and maintained by Cybrosys Technologies, an Odoo-focused software development company headquartered in Kozhikode (Calicut), Kerala, India. The project extends beyond core HR into CRM territory, giving small and mid-sized businesses a single self-hostable platform to manage recruitment, onboarding, employee records, attendance, leave, assets, payroll, performance reviews, and offboarding, alongside sales-pipeline and lead-management CRM modules. Horilla is released under the LGPL-2.1 license and distributed as source code on GitHub at horilla/horilla-hr, where it has attracted an active community of contributors who file issues, submit pull requests, and build custom modules on top of its Python/Django backend. Because Cybrosys built its reputation as an official Odoo implementation partner, Horilla's architecture and admin UX borrow familiar patterns from ERP-style business software: modular apps, role-based permissions, configurable workflows, and a REST API for integrating with payroll processors, accounting tools, and third-party job boards. Horilla ships in three ways. The self-hosted, fully open-source edition is free forever, giving organizations unlimited users and companies, full source-code access, community support through GitHub, and all future updates, at the cost of provisioning and maintaining the servers themselves. Horilla Cloud is a managed tier priced from $7 per user per month, billed monthly with a 30-day free trial, including daily backups, zero-downtime auto-updates, SSL with a custom domain, priority email support with a 48-hour SLA, and a 99.9 percent uptime guarantee, aimed at teams who want the open-source feature set without running their own infrastructure. An Enterprise tier adds custom, quote-based pricing for large organizations needing on-premises or private-cloud deployment, single sign-on via SAML 2.0, OAuth, or LDAP, a dedicated account manager, a 4-hour response SLA with 99.95 percent uptime, white-labeling, custom integrations, and priority implementation support. All three tiers expose the same core HRMS and CRM modules; the differentiation is purely around hosting, support, and compliance requirements. Horilla's target audience is cost-conscious HR and operations teams, particularly at SMBs, agencies, and IT-savvy organizations, who want the depth of a commercial HRIS comparable to BambooHR or Zoho People without recurring per-employee SaaS fees, and who are comfortable either self-hosting a Django application or paying a modest per-user fee for a managed instance. It competes directly with other open-source HR platforms such as OrangeHRM and Frappe HR (ERPNext HR), as well as proprietary SMB-focused HRIS tools like BambooHR, Zoho People, and Gusto. Horilla differentiates primarily on its zero-cost self-hosted option, its combined HR-plus-CRM scope, and its Odoo-informed, module-based architecture from a development team with over a decade of enterprise-software delivery experience. Community reviews generally highlight Horilla's broad feature coverage relative to price, an active GitHub development cadence, and an approachable UI, while noting that documentation and third-party integrations are still maturing compared to long-established incumbents, and that support quality depends heavily on which tier a customer chooses. Because Cybrosys' core business is Odoo consulting and customization, Horilla also functions as a lead-generation vehicle: organizations that outgrow the open-source defaults can hire Cybrosys directly for custom module development, migrations, and hosted deployments, a common commercial pattern among open-source-first software vendors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6c4d248e-ed75-425f-a74f-2cfa5f36dc03';

