-- ── HortusFox ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$HortusFox is a free, self-hosted, open-source plant collection manager for tracking and caring for houseplants collaboratively.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HortusFox Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$HortusFox is a free, self-hosted, open-source plant tracking app. See 2026 features, pricing, pros, cons, and alternatives for plant collectors.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HortusFox is a self-hosted, open-source plant collection management platform built for plant enthusiasts who want a private, ad-free alternative to closed commercial houseplant-tracking apps. It was created by developer Daniel Brendel and is maintained under the hortusfox GitHub organization, with the main source repository at danielbrendel/hortusfox-web. The project is written in PHP with a MariaDB or MySQL database backend and ships as a progressive web app, so it can be installed on a phone's home screen and used offline-friendly without a native App Store or Play Store listing. Because it is self-hosted, HortusFox has no company behind it in the traditional SaaS sense; there is no headquarters, no funding round, and no subscription business model. Instead it is licensed under the permissive MIT license and distributed entirely for free as source code that anyone can deploy on their own server, a home lab, or a low-cost VPS. Users typically install it via Docker, a one-click app on platforms like Cloudron or elest.io, or manually on a LAMP-style stack. The core feature set centers on cataloging: users add individual plants with photos, species details, acquisition dates, and locations within their home or garden, then organize them by rooms or zones on a visual dashboard. A built-in care and warning system flags plants that need watering, fertilizing, or repotting based on user-defined schedules, and a calendar view consolidates upcoming care tasks. Because HortusFox was built with collaboration in mind, it supports multiple user accounts with authentication, shared access to a household or community plant collection, an internal group chat for discussing plant care, and a history log that records who took what action and when, which is unusual depth for a plant-tracking tool. Additional features include an inventory system for tracking soil, pots, and supplies, full-text search across the collection, weather integration for outdoor plant care reminders, customizable user profiles and themes, admin-level controls for managing multi-user instances, and, as of version 3.1, a REST API that allows developers to build integrations or automations, such as feeding plant data into home-automation systems. HortusFox's target audience is technically comfortable plant hobbyists, community garden organizers, plant shops, and privacy-conscious users who are uncomfortable uploading photos and location data about their homes to a commercial cloud app and would rather run their own instance. It competes with consumer plant-care apps like Planta, Vera, and Greg, as well as with general-purpose collection trackers repurposed for plants; HortusFox differentiates sharply on being fully open source, self-hosted, free of subscription fees or ads, and collaborative by design, at the cost of requiring the user (or a friend) to handle server setup and maintenance rather than simply downloading an app from a store. There is no publicly documented founding year, company size, or headquarters for the project because it operates as a community-maintained open-source codebase rather than a registered company, and third-party commercial hosting of HortusFox instances (for users who don't want to self-host) is explicitly disclaimed by the project as being outside its responsibility.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a0a11055-ce1c-48de-8c3b-a99cd8a998eb';

