-- ── Hotjar ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Hotjar is a behavior analytics platform offering heatmaps, session recordings, and surveys to understand website user behavior.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Observe Basic); paid plans from $39/month$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$190-1,000+ employees (part of Contentsquare)$q$, company_size),
  headquarters = COALESCE($q$Malta$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Hotjar Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Hotjar offers heatmaps, session recordings, and surveys to reveal how users interact with your site. See 2026 pricing, features, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Hotjar is a behavior analytics and user feedback platform founded in 2014 in Malta by David Darmanin, who serves as founder and chairman, alongside co-founders including Erik Naslund, Johan Malmberg, Marc von Brockdorff, and Jonathan Vella. The company was self-funded and built as a fully remote, distributed organization from its earliest days, eventually growing to more than 190 team members spread across roughly 33 countries in Europe, the Americas, and Africa. On September 1, 2021, digital experience analytics company Contentsquare announced it was acquiring Hotjar, its sixth acquisition within two years, forming a combined organization of more than 1,000 employees; Hotjar has continued operating as a distinct product brand within Contentsquare rather than being immediately merged away. Technically, Hotjar works by embedding a lightweight JavaScript tracking snippet on a website, which then records anonymized or pseudonymized visitor interactions, mouse movements, clicks, scrolling, and page navigation, and aggregates them into two main product areas: Observe and Ask. Observe covers heatmaps that visualize where users click, move, and scroll on a page, along with session recordings that let teams replay individual visitor sessions to spot friction, rage clicks, and dead clicks. Ask covers on-site surveys and feedback widgets that let teams collect qualitative, in-context responses from real visitors, plus recruiting panels for user interviews. Hotjar Surveys, marketed at hotjar.com/surveys, is the flagship feature within the Ask product line and lets teams build fully responsive, no-code surveys distributed via an embedded on-page widget, a shareable link, or email, with GDPR and CCPA-aligned data handling; the company reports having collected feedback from over 402 million respondents across more than 180 countries, and states that Hotjar as a whole is used on more than 1.3 million websites, including large brands such as Nintendo, Adobe, T-Mobile, and HubSpot. Historically, Hotjar priced Observe and Ask as separate self-serve subscriptions, each on a free Basic tier and three paid tiers (Plus, Business, and Scale) scaled by daily session volume for Observe (roughly $39, $99, and $213 per month respectively at monthly billing, cheaper annually) and by monthly response volume for Ask (roughly EUR 48, EUR 64, and EUR 128 per month). As of 2026, Contentsquare has begun migrating Hotjar's self-serve customers onto a unified Contentsquare pricing structure with Growth, Pro, and Enterprise tiers, with Growth starting around $49 per month and Pro and Enterprise requiring custom quotes, reflecting the platforms' post-acquisition consolidation. Hotjar's target audience spans UX researchers, product managers, conversion rate optimization specialists, marketers, and growth teams at small to mid-market companies who want fast, visual, qualitative insight into user behavior without the complexity of a full digital experience analytics suite. Its most direct competitors include Microsoft Clarity, which offers a free alternative for heatmaps and recordings, as well as Crazy Egg, FullStory, Mouseflow, and Lucky Orange; Hotjar differentiates through its combined recordings-plus-surveys workflow, ease of setup, and brand recognition as one of the earliest mainstream heatmap tools, though reviewers note session-volume caps on lower tiers, ticket-based support with one-to-two-business-day response times, and limited cross-site analysis as recurring limitations relative to more enterprise-grade competitors.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '65ed3bfb-065e-4391-8e0f-5ffc7b205daa';

