-- ── Hotjar Surveys ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Hotjar Surveys lets teams build no-code, responsive on-site or email surveys to collect direct feedback from website visitors.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (20 responses/month); paid plans from approximately EUR 48/month$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$190-1,000+ employees (part of Contentsquare)$q$, company_size),
  headquarters = COALESCE($q$Malta$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Hotjar Surveys Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Hotjar Surveys is a no-code survey tool for collecting on-site visitor feedback. See 2026 pricing, features, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Hotjar Surveys is the survey and feedback-collection feature within Hotjar's Ask product line, built by Hotjar, a behavior analytics company founded in 2014 in Malta by David Darmanin and co-founders including Erik Naslund, Johan Malmberg, Marc von Brockdorff, and Jonathan Vella. Hotjar operated as a fully remote, self-funded startup for years before being acquired by digital experience analytics company Contentsquare in September 2021, after which it continued operating under its own brand within a combined organization of more than 1,000 employees. Hotjar Surveys lets marketing, product, and UX teams build fully responsive surveys using a no-code editor, then distribute them either as an on-site widget triggered by page rules and visitor behavior, as a standalone shareable link, or via email, making it flexible enough to gather feedback both in-context on a live website and out-of-context from an existing customer list. The product handles response storage permanently on paid plans, includes logic for skipping or branching questions based on prior answers, and is built with GDPR and CCPA compliance in mind, including anonymization and data-retention controls appropriate for European and North American privacy regulations. According to Hotjar's own reporting, the surveys product has collected feedback from more than 402 million respondents across over 180 countries, and Hotjar as a whole, including Surveys, is used on more than 1.3 million websites by brands such as Nintendo, Adobe, T-Mobile, and HubSpot, with tens of thousands of new signups occurring monthly. Hotjar Surveys operates on a freemium model requiring no credit card to start: the free Basic tier allows up to 20 survey responses per month, sufficient for early-stage testing or low-traffic sites, while paid tiers unlock unlimited surveys and higher response caps. Historically, Ask's paid tiers were priced separately from Observe (Hotjar's heatmaps and recordings product) at roughly EUR 48 per month for Plus (250 responses), EUR 64 per month for Business (500 responses), and EUR 128 per month for Scale (higher volumes with more advanced feedback tooling); Hotjar is migrating self-serve customers throughout 2026 onto a unified Contentsquare pricing structure with Growth, Pro, and Enterprise tiers. Hotjar Surveys is most useful for growth and product teams that want direct, qualitative context to pair with quantitative behavior data from heatmaps and session recordings, letting them ask visitors why they behaved a certain way rather than only observing what they did. Its closest competitors include dedicated survey tools like Typeform, SurveyMonkey, and Qualaroo, as well as feedback features built into other analytics platforms such as FullStory and Mouseflow; Hotjar Surveys differentiates by being tightly integrated with Hotjar's broader behavior analytics suite, allowing teams to trigger surveys based on the same visitor session data used for heatmaps and recordings, and by its very large respondent network drawn from Hotjar's installed base across 1.3 million websites, though it lacks some of the advanced branching logic and dedicated research-panel tooling found in standalone survey specialists.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '00ea990a-f3f1-4733-b437-22705a46609d';

