-- ── HTMLy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$HTMLy is a free, open-source, databaseless PHP blogging platform and flat-file CMS that requires no database to run.$q$, short_description),
  pricing_model = COALESCE($q$Open Source / Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HTMLy Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$HTMLy is a free, open-source, databaseless PHP blogging platform. See 2026 features, pricing, pros, cons, and alternatives for flat-file CMS users.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HTMLy is an open-source, databaseless blogging platform and flat-file content management system built in PHP, created and maintained by a developer known as DanPros, with source code hosted publicly at github.com/danpros/htmly. Rather than storing posts in a MySQL or other relational database, HTMLy stores every article as a plain text file on the server's file system using Markdown-like formatting, then uses a custom indexing algorithm to organize and retrieve content by date, category, tag, or author. The project's core selling point is architectural simplicity: because there is no database layer to install, configure, back up, or secure, HTMLy can run on extremely modest infrastructure, including shared hosting plans with as little as 512 MB of RAM, while the project states its indexing approach remains fast even with more than 20,000 posts and hundreds of tags. HTMLy is licensed under the GNU General Public License version 2 or later, making it fully free to download, modify, and redistribute, with no company, funding history, or commercial entity behind it beyond its open-source maintainer and contributor community; as a result, there is no confirmed public founding year, headquarters, or company size associated with the project, distinguishing it from venture-backed blogging SaaS products. System requirements are minimal: PHP 7.2 or higher along with the Mbstring, XML, Intl, and GD extensions, plus the ZIP extension if administrators want to use HTMLy's built-in backup functionality. Feature-wise, HTMLy supports archives, categories, tags, and automatic XML sitemap generation for SEO, full-text search across the entire post library, two-factor authentication for the admin login, scheduled publishing for posts written in advance, custom fields for extending post metadata, a menu editor with one-click updates, and built-in tracking of popular posts. Installation can be done either by downloading the source from GitHub directly or by using HTMLy's online installer script, which pulls the latest release automatically, making setup accessible even to users without command-line experience. HTMLy's target audience is developers, technical bloggers, and website owners who want a lightweight, fast, and low-maintenance publishing platform without the overhead, attack surface, and hosting requirements of a database-driven CMS like WordPress; it is particularly popular among users running personal tech blogs, documentation sites, and portfolio blogs on cheap or free shared hosting where a full LAMP-stack CMS would be unnecessarily heavy. It competes with other flat-file and static-adjacent publishing tools such as Grav, Kirby, Jekyll, Hugo, and Ghost, as well as, at a much larger scale, WordPress; HTMLy differentiates by staying true to a pure PHP, no-build-step, no-database model that non-technical users can still deploy on ordinary shared hosting without a static site generator's command-line build process, while sacrificing some of the plugin ecosystem, theme marketplace, and multi-author collaboration tooling that database-backed platforms like WordPress and Ghost offer at scale.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c23263cf-333f-4561-ac68-e421277a1f58';

