-- ── HTTPie ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$HTTPie is a user-friendly HTTP client and API testing tool available as an open-source CLI and a desktop and web app.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (Open Source CLI, plus paid team and enterprise features)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$HTTPie Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$HTTPie is a user-friendly API testing client with a free CLI and desktop app. See 2026 pricing, features, pros, cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$HTTPie began in 2012 as an open-source command-line HTTP client created by developer Jakub Roztocil, built as a more human-friendly alternative to curl for interacting with web APIs from the terminal. Written in Python and using the Requests and Pygments libraries under the hood, the original httpie command popularized colorized, readable JSON output, intuitive syntax for setting headers and request bodies, and sensible defaults, which drove it to become one of the most-starred command-line tools on GitHub, with the core httpie/httpie repository amassing tens of thousands of stars. Roztocil later formalized the open-source project into a company, HTTPie Inc., headquartered in San Francisco, California, with Roztocil continuing as Founder and CEO. In 2020, the company raised a 6.5 million dollar seed funding round led by Coatue, with participation from Blossom Capital and angel investors who were founders of Intercom, Checkout.com, and Monzo, funding the expansion from a single CLI tool into a broader API development platform. That platform now includes HTTPie Desktop and HTTPie for Web, a cross-platform GUI application available for macOS (both Intel and Apple Silicon), Windows, and Linux, as well as a browser-based version, both of which layer a visual interface, request history, collections, environment variables, and team collaboration features on top of the same request engine that powers the CLI. More recently, the company has added HTTPie AI, an AI assistant aimed at helping developers generate, debug, and document API requests throughout the API lifecycle. Architecturally, HTTPie's product line spans three surfaces: the original open-source terminal client, installable via package managers like apt, brew, and pip; the newer desktop and web GUI, which was in public beta as of the company's most recent releases; and cloud-connected team features for sharing collections and environments across an organization. The terminal client remains fully free and open source with no paid tier, reflecting its role as both the company's original product and its primary developer-acquisition channel, while the desktop and web app is free for individual use and reserves collaborative, team-oriented functionality for paid plans; HTTPie does not publish detailed self-serve pricing for its team and enterprise tiers, instead directing prospective business customers to contact sales for custom quotes, a common pattern among open-source-rooted developer tools monetizing through a top-of-funnel free product. HTTPie's target audience spans individual developers and hobbyists who rely on the free CLI or desktop app for everyday API testing, up through engineering teams and enterprises that need shared collections, environment management, and collaboration features for testing REST, GraphQL, and general HTTP APIs together. Its most direct competitors are Postman, the dominant player in the API client space, along with Insomnia, Thunder Client, Bruno, and the open-source Hoppscotch; HTTPie differentiates through its command-line-first heritage and reputation for simplicity and readability, its fully open-source terminal client with no feature gating, and a lighter-weight, more developer-centric desktop experience relative to Postman's broader but heavier feature set, though it has a smaller collaboration and enterprise feature set than Postman given Postman's longer head start monetizing team workflows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f1c58995-800c-4ef6-9481-0dcaa3734eff';

